DELETE FROM packages WHERE destination_slug = 'thailand';

-- ── 1. Bangkok & Pattaya ─────────────────────────────────────────────────────
INSERT INTO packages (
  title, slug, description, category, destination, destination_slug,
  price, original_price, duration, nights, days, location, image_url, gallery,
  itinerary, highlights, inclusions, exclusions, know_before, route,
  rating, review_count, meta_title, meta_description, keywords
)
SELECT
  'Bangkok & Pattaya Classic Escape',
  'bangkok-pattaya-classic-escape-5d',
  'A perfect introduction to Thailand, combining the high-energy urban life of Bangkok with the coastal charm and vibrant nightlife of Pattaya.',
  'international', 'Thailand', 'thailand',
  28500, 35000, '4 Nights / 5 Days', 4, 5,
  'Bangkok, Pattaya', '/images/placeholder.svg', '[]'::jsonb,
  '[{"day":1,"title":"Arrival in Bangkok","description":"Upon arrival at Suvarnabhumi Airport, you will be met by our representative for a comfortable private transfer to your hotel. After checking in, take some time to refresh and unwind from your journey while enjoying the hotel amenities. As evening approaches, head out for a scenic cruise along the Chao Phraya River, where you will dine while watching the city lights. This is the perfect introduction to the vibrant Thai capital, offering stunning views of temples and skyscrapers along the waterfront."},{"day":2,"title":"Bangkok City Tour","description":"Start your morning with a visit to the Grand Palace, an architectural marvel and the official residence of the Thai Kings. Continue your cultural journey to Wat Arun, the iconic Temple of Dawn, known for its intricate porcelain spires reflecting the morning light. Spend the afternoon exploring the bustling shopping districts of Siam Paragon or MBK Center, where you can find everything from luxury brands to unique local souvenirs. Conclude your day with a traditional Thai massage to relax your muscles after a full day of sightseeing and walking through the city."},{"day":3,"title":"Transfer to Pattaya","description":"Check out from your Bangkok hotel and enjoy a comfortable, scenic drive eastward to the coastal city of Pattaya. Upon arrival, visit the Sanctuary of Truth, a breathtaking wooden temple constructed entirely without metal nails, showcasing incredible craftsmanship. Afterward, head to your hotel and take some time to enjoy the beachfront atmosphere or grab a refreshing drink at a seaside bar. As the sun sets, immerse yourself in the energetic nightlife of Pattaya, walking through the famous Walking Street to witness its legendary street performances and lively crowds."},{"day":4,"title":"Coral Island Adventure","description":"Board a private speedboat early in the morning for a thrilling ride to the beautiful Coral Island, also known as Koh Larn. Spend your day enjoying pristine white sands, crystal-clear turquoise waters, and an array of exciting water sports like parasailing and snorkeling. Relax on your sun lounger with a cold drink, soaking in the tropical sun while enjoying the panoramic ocean views around you. Return to the mainland in the late afternoon, leaving time for a final delicious seafood dinner at a local restaurant overlooking the Gulf of Thailand."},{"day":5,"title":"Departure","description":"Enjoy a final leisurely breakfast at the hotel, savoring the flavors of local Thai fruit and freshly brewed coffee. Take advantage of your remaining time to do some last-minute shopping for gifts or mementos at nearby local markets. Our representative will pick you up at the scheduled time to ensure a stress-free and timely transfer to Bangkok International Airport. As you head home, take with you beautiful memories of Thailand and the wonderful experiences you encountered throughout your journey."}]'::jsonb,
  '["Chao Phraya River Cruise","Grand Palace & Wat Arun","Coral Island water sports","Sanctuary of Truth","Shopping in Bangkok"]'::jsonb,
  '["4 nights hotel accommodation","Daily breakfast","All private transfers","Sightseeing entrance fees","English speaking local guide"]'::jsonb,
  '["International airfare","Visa fees","Lunch and dinner","Personal shopping","Tips"]'::jsonb,
  '["Pack modest attire for temple visits (shoulders and knees covered)","Book water sports via authorized operators only"]'::jsonb,
  '["Bangkok","Pattaya"]'::jsonb,
  4.5, 850,
  'Bangkok & Pattaya Tour | 360 Travellers',
  'Book your Bangkok & Pattaya getaway from ₹28,500. City life, culture & beaches.',
  '["bangkok tour","pattaya package","thailand travel","360 travellers"]'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM packages WHERE slug = 'bangkok-pattaya-classic-escape-5d');

-- ── 2. Phuket & Krabi ────────────────────────────────────────────────────────
INSERT INTO packages (
  title, slug, description, category, destination, destination_slug,
  price, original_price, duration, nights, days, location, image_url, gallery,
  itinerary, highlights, inclusions, exclusions, know_before, route,
  rating, review_count, meta_title, meta_description, keywords
)
SELECT
  'Phuket & Krabi Tropical Bliss',
  'phuket-krabi-tropical-bliss-6d',
  'Experience the ultimate Andaman coastal journey with stunning limestone cliffs, emerald lagoons, and the vibrant beach culture of Phuket.',
  'international', 'Thailand', 'thailand',
  35000, 42000, '5 Nights / 6 Days', 5, 6,
  'Phuket, Krabi', '/images/placeholder.svg', '[]'::jsonb,
  '[{"day":1,"title":"Arrival in Phuket","description":"Arrive at Phuket International Airport and be warmly greeted by our team for your transfer to a luxury beachfront resort. Spend the remainder of your first day relaxing by the pool or taking a stroll along the soft sands of Patong Beach. As the evening sets in, explore the vibrant nightlife along Bangla Road, where the streets come alive with music and lights. Enjoy a late dinner at a local cafe to taste the authentic flavors of Southern Thai cuisine for the first time."},{"day":2,"title":"Phi Phi Islands Excursion","description":"Set off early for a full-day speedboat adventure to the world-famous Phi Phi Islands, a stunning archipelago in the Andaman Sea. Explore the emerald waters of Maya Bay, made famous by Hollywood, and stop at Viking Cave to see ancient paintings and swiftlet nests. Enjoy hours of snorkeling in vibrant coral reefs where you can swim alongside schools of colorful tropical fish in crystal-clear water. A picnic lunch will be served on the beach, allowing you to relax under the shade of palm trees before heading back to Phuket."},{"day":3,"title":"Transfer to Krabi","description":"Check out from your Phuket resort and enjoy a scenic, comfortable land transfer to the picturesque coastal province of Krabi. On the way, stop at scenic viewpoints to capture the breathtaking beauty of the Andaman coastline against the blue sky. Upon arriving in the Ao Nang area, check into your hotel and enjoy a refreshing welcome drink while taking in the views of limestone karst formations. Spend your evening walking along the beach promenade, finding the perfect spot to watch the sun dip below the horizon over the ocean."},{"day":4,"title":"Four Island Tour","description":"Board a traditional long-tail boat for an intimate island-hopping tour to Koh Poda, Chicken Island, Koh Tub, and Koh Mor. These islands offer some of the most beautiful photo opportunities in Krabi, with sandbars connecting the islands at low tide. Spend your day swimming in shallow waters, sunbathing on pristine white sand, and exploring the unique rock formations found in this marine sanctuary. Enjoy a packed picnic lunch on the beach, surrounded by the peaceful atmosphere and stunning natural landscapes that make Krabi a top destination."},{"day":5,"title":"Krabi Relaxation","description":"Today is yours to spend exactly as you please, whether that means total relaxation or further discovery of Krabi. You might choose to visit the famous Emerald Pool and Hot Springs, nestled in the heart of a lush tropical jungle. Alternatively, consider an adventurous kayaking trip through the dense mangrove forests where you can see local wildlife up close. Treat yourself to a final indulgent beachside farewell dinner under the stars, reflecting on the amazing sights and sounds you experienced during your stay."},{"day":6,"title":"Departure","description":"Savor one final hearty breakfast at the hotel, enjoying the tropical fruit and calm morning air by the beach. Take some time to pack your bags and pick up any last-minute souvenirs from local boutiques nearby. Our team will provide a private transfer to Krabi International Airport, ensuring you reach your terminal well in advance for your flight home. Depart with incredible memories of Thailand most beautiful islands, knowing that you have experienced the very best of the Andaman coast."}]'::jsonb,
  '["Phi Phi Islands speedboat tour","Maya Bay visit","Krabi Four Island hopping","Limestone cliff scenery","Emerald Pool tour"]'::jsonb,
  '["5 nights accommodation","Daily breakfast","All ground transfers","Speedboat & long-tail boat tours","Local guide services"]'::jsonb,
  '["International flights","Visa fees","Lunch and dinner","Personal expenses","Travel insurance"]'::jsonb,
  '["High-SPF sunscreen is essential","Check tide timings for island hopping","Respect marine conservation rules"]'::jsonb,
  '["Phuket","Krabi"]'::jsonb,
  4.8, 620,
  'Phuket & Krabi Beach Tour | 360 Travellers',
  'Experience island life in Phuket and Krabi. Book now with 360 Travellers.',
  '["phuket tour","krabi package","thailand beaches","360 travellers"]'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM packages WHERE slug = 'phuket-krabi-tropical-bliss-6d');

-- ── 3. Chiang Mai & Chiang Rai ───────────────────────────────────────────────
INSERT INTO packages (
  title, slug, description, category, destination, destination_slug,
  price, original_price, duration, nights, days, location, image_url, gallery,
  itinerary, highlights, inclusions, exclusions, know_before, route,
  rating, review_count, meta_title, meta_description, keywords
)
SELECT
  'Cultural Northern Thailand',
  'cultural-northern-thailand-7d',
  'Discover the spiritual and cultural heart of Thailand. Visit ancient temples, meet majestic elephants, and explore the serene mountains of the north.',
  'international', 'Thailand', 'thailand',
  32000, 40000, '6 Nights / 7 Days', 6, 7,
  'Chiang Mai, Chiang Rai', '/images/placeholder.svg', '[]'::jsonb,
  '[{"day":1,"title":"Arrival in Chiang Mai","description":"Arrive at the charming Chiang Mai International Airport and receive a warm welcome from our team before your transfer to your hotel. Once checked in, take some time to explore the immediate surroundings of the Old City, filled with ancient walls and moats. In the evening, head straight to the famous Chiang Mai Night Bazaar, a sensory delight of lights and local energy. Sample some authentic northern Thai street food like Khao Soi, and browse through stalls filled with beautiful handmade silk and hill-tribe crafts."},{"day":2,"title":"Temple & Culture Day","description":"Begin your day by ascending the mountain to the iconic Wat Phra That Doi Suthep, a golden temple that offers a breathtaking panoramic view of the entire city. After descending, spend your afternoon wandering through the historic streets of the Old City, visiting ancient temple ruins that date back hundreds of years. Learn about the peaceful way of life in the north and the deep-rooted Buddhist traditions that govern the daily activities here. As the sun sets, consider a quiet walk around a local temple garden, soaking in the serene, spiritual atmosphere."},{"day":3,"title":"Elephant Sanctuary","description":"Travel to a reputable, ethical elephant sanctuary located in the lush green mountains, where you will spend a memorable full day. Learn the fascinating history of Asian elephants and observe how the sanctuary focuses on conservation and natural welfare rather than entertainment. You will have the unique opportunity to feed the elephants and walk alongside them as they wander freely in their natural habitat. Participate in a gentle bathing session in a mud pit or river, creating an unforgettable bond with these magnificent and intelligent creatures."},{"day":4,"title":"Journey to Chiang Rai","description":"Depart from Chiang Mai and embark on a scenic drive north, winding through misty mountain passes that offer incredible views of the rural landscape. Along the way, stop at a local village inhabited by the Karen Long Neck tribe, where you can learn about their unique traditions and way of life. Continue your drive to Chiang Rai, a city known for its laid-back pace and artistic spirit. Upon arrival, check into your accommodation and enjoy a peaceful evening dining by the banks of the Kok River, reflecting on the beauty of northern Thailand."},{"day":5,"title":"The White Temple","description":"Visit the legendary Wat Rong Khun, also known as the White Temple, famous for its surreal design, glittering glass mosaics, and modern artistic interpretations. Marvel at the intricate details that cover every inch of the structure, making it one of the most unique and photogenic sites in all of Asia. Afterward, continue to the Blue Temple, which offers a striking contrast with its deep cobalt tones and elaborate golden statues. Spend your afternoon wandering through the tranquil grounds of these artistic masterpieces, appreciating the creativity of local Thai architects."},{"day":6,"title":"Golden Triangle","description":"Travel to the historic Golden Triangle, the fabled point where the borders of Thailand, Laos, and Myanmar converge along the Mekong River. Take a peaceful river boat tour that allows you to see the three countries from the water, providing a unique perspective on this legendary region. Explore the local Opium Museum to learn about the fascinating, sometimes dark history of this area and how it has transformed into a peaceful tourist destination. End your day with a sunset dinner in a local town, surrounded by the beautiful rolling hills of the north."},{"day":7,"title":"Departure","description":"Enjoy a slow and peaceful breakfast at your hotel, savoring the cool morning air and the lush scenery of the north one last time. Pack your bags, ensuring you have space for all the beautiful handicrafts and mementos you collected during your trip. Our representative will pick you up and transfer you to the Chiang Rai airport in plenty of time for your flight. As you take off, you will carry with you the peaceful memories of Thailand cultural heart and the kindness of the northern people."}]'::jsonb,
  '["Doi Suthep Temple","Ethical Elephant Sanctuary","White & Blue Temples","Golden Triangle boat tour","Karen Long Neck Village"]'::jsonb,
  '["6 nights boutique hotel stay","Daily breakfast","All private sightseeing transfers","Sanctuary entrance fees","Knowledgeable local guide"]'::jsonb,
  '["Flights","Visa","Lunch and dinner","Tips","Travel insurance"]'::jsonb,
  '["Temperatures can be cooler in the mountains; pack a light jacket","Respect temple silence rules"]'::jsonb,
  '["Chiang Mai","Chiang Rai"]'::jsonb,
  4.7, 450,
  'Northern Thailand Culture Tour | 360 Travellers',
  'Explore the cultural heart of Thailand. Book your trip with 360 Travellers.',
  '["chiang mai tour","chiang rai package","thailand culture","360 travellers"]'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM packages WHERE slug = 'cultural-northern-thailand-7d');

-- ── 4. Complete Thailand ──────────────────────────────────────────────────────
INSERT INTO packages (
  title, slug, description, category, destination, destination_slug,
  price, original_price, duration, nights, days, location, image_url, gallery,
  itinerary, highlights, inclusions, exclusions, know_before, route,
  rating, review_count, meta_title, meta_description, keywords
)
SELECT
  'The Complete Thailand Experience',
  'complete-thailand-experience-10d',
  'An immersive 10-day journey covering the bustling capital, the serene cultural north, and the breathtaking southern beaches.',
  'international', 'Thailand', 'thailand',
  65000, 80000, '9 Nights / 10 Days', 9, 10,
  'Bangkok, Chiang Mai, Phuket', '/images/placeholder.svg', '[]'::jsonb,
  '[{"day":1,"title":"Bangkok Arrival","description":"Land at Bangkok International Airport and receive a warm welcome before being transferred to your luxury hotel. Spend your first evening relaxing after your flight, perhaps enjoying a refreshing swim in the hotel pool. Take a short, gentle walk around the nearby streets to get a feel for the city electric atmosphere. End the night with a quiet, delicious meal at a local restaurant to prepare for your exciting adventure ahead."},{"day":2,"title":"Bangkok City Wonders","description":"Start your day with a visit to the magnificent Grand Palace, home to breathtaking architecture and the revered Emerald Buddha. Wander through the bustling streets of Chinatown, where the vibrant colors and aromas of street food create a sensory experience. In the afternoon, take a boat trip through the historic khlongs (canals) to see a more traditional side of the capital. Spend your evening shopping at high-end malls or local night markets to find the perfect souvenirs to take home."},{"day":3,"title":"Flight to Chiang Mai","description":"After breakfast, you will be transferred to the airport for your short domestic flight to the cultural capital of Chiang Mai. Upon arrival, check into your boutique hotel and take some time to settle into the quieter, more relaxed northern vibe. In the evening, immerse yourself in a traditional Khantoke dinner, where you will enjoy local delicacies while watching cultural dance performances. This is the perfect way to begin your deep dive into the unique traditions and artistic heritage of northern Thailand."},{"day":4,"title":"Northern Exploration","description":"Spend your morning visiting the golden Wat Phra That Doi Suthep, a stunning temple perched high atop a mountain overlooking the valley. In the afternoon, head to a well-regarded elephant sanctuary to learn about animal conservation and enjoy peaceful time with these gentle giants. Engage in ethical interactions such as feeding and bathing the elephants in a natural, respectful environment. Return to the city for a quiet dinner, enjoying the serene atmosphere of the north and the cool evening breeze."},{"day":5,"title":"Flight to Phuket","description":"After breakfast, enjoy one last stroll through the charming streets of Chiang Mai before heading to the airport for your flight to the south. Arrive in Phuket and be transferred to your beachfront resort, where the sound of the ocean greets you immediately. Spend your afternoon relaxing on the sand or taking a refreshing dip in the warm Andaman Sea. Enjoy a spectacular sunset dinner at a beach club, setting the tone for the relaxing beach days that lie ahead of you."},{"day":6,"title":"Phi Phi Adventure","description":"Embark on a full-day speedboat tour that will take you to the famous Phi Phi Islands, known for their dramatic limestone cliffs and clear waters. Visit Maya Bay, where you can take photos, and stop at quiet coves for hours of incredible snorkeling and swimming. Enjoy a delicious buffet lunch on a private island, surrounded by some of the most beautiful ocean scenery in the world. Spend your afternoon island hopping, discovering hidden beaches and secret lagoons before returning to Phuket by boat."},{"day":7,"title":"Island Relaxation","description":"Today is a day of pure relaxation, allowing you to enjoy the luxury of your resort or explore the hidden corners of Phuket at your own pace. Consider a rejuvenating Thai spa treatment, famous worldwide for its healing and relaxing properties, to refresh your body. Alternatively, spend your afternoon in the historic Phuket Old Town, where you can admire the unique Sino-Portuguese architecture and visit local art galleries. As evening arrives, treat yourself to a gourmet dinner at a seaside restaurant, watching the lights of boats twinkle on the horizon."},{"day":8,"title":"Water Activities","description":"Today offers an opportunity for adventure, with options like scuba diving at world-class reefs or a day trip to the pristine Similan Islands. If you prefer to stay closer to base, enjoy renting a sea kayak to explore the quiet coves and hidden sea caves near the coast. Spend your afternoon relaxing on a sun lounger, reading a book, or sipping a cool coconut under the shade of a beach umbrella. As the sun sets, enjoy one final vibrant night in Phuket, celebrating the end of your island stay."},{"day":9,"title":"Return to Bangkok","description":"After a final morning beach breakfast, you will be transferred to Phuket airport for your return flight to Bangkok. Once you land, check back into your hotel and take the opportunity for some final shopping at Bangkok famous weekend markets or modern malls. Reflect on your incredible journey across the country, from the temples of the north to the beaches of the south. Spend your last evening in Thailand enjoying a fancy dinner to celebrate the end of an unforgettable, comprehensive experience."},{"day":10,"title":"Departure","description":"Enjoy a final, leisurely breakfast in the heart of Bangkok before preparing for your return journey home. Take a moment to pack your bags and ensure you have all your treasures and memories safely stowed. Our representative will arrive at your hotel for your private transfer to the international airport in plenty of time for your flight. We hope you leave Thailand with a heart full of memories and a desire to return to this beautiful country in the near future."}]'::jsonb,
  '["Comprehensive Thailand coverage","Grand Palace","Ethical elephant interaction","Phi Phi island hopping","Sino-Portuguese architecture"]'::jsonb,
  '["9 nights accommodation","Daily breakfast","Internal domestic flights","All transfers","Guided tours"]'::jsonb,
  '["International flights","Visa fees","Lunch and dinner","Personal expenses"]'::jsonb,
  '["Book internal flights well in advance","Pack a variety of clothes for city, mountains, and beach"]'::jsonb,
  '["Bangkok","Chiang Mai","Phuket"]'::jsonb,
  4.9, 1200,
  'Complete Thailand Tour | 360 Travellers',
  'From city to beach, cover all of Thailand. Book with 360 Travellers.',
  '["thailand tour package","complete thailand","thailand vacation","360 travellers"]'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM packages WHERE slug = 'complete-thailand-experience-10d');

-- ── 5. Koh Samui Island Adventure ────────────────────────────────────────────
INSERT INTO packages (
  title, slug, description, category, destination, destination_slug,
  price, original_price, duration, nights, days, location, image_url, gallery,
  itinerary, highlights, inclusions, exclusions, know_before, route,
  rating, review_count, meta_title, meta_description, keywords
)
SELECT
  'Samui Island Adventure',
  'samui-island-adventure-7d',
  'Escape to the Gulf of Thailand for luxury resorts, pristine beaches, and vibrant island-hopping adventures.',
  'international', 'Thailand', 'thailand',
  42000, 52000, '6 Nights / 7 Days', 6, 7,
  'Koh Samui, Koh Phangan', '/images/placeholder.svg', '[]'::jsonb,
  '[{"day":1,"title":"Arrival in Koh Samui","description":"Land at the unique, open-air Samui International Airport and receive a warm tropical welcome. Transfer to your luxury beachfront resort and immediately feel the stress melt away as you check in. Spend the rest of your day lounging by the pool or taking a refreshing walk along the white sands of the beach. As the evening arrives, settle in for a beautiful sunset dinner, enjoying fresh local cuisine while listening to the gentle sound of the Gulf of Thailand waves."},{"day":2,"title":"Ang Thong Marine Park","description":"Set off on an exciting full-day boat tour to Ang Thong National Marine Park, a protected archipelago of 42 islands. Explore hidden saltwater lagoons, go kayaking through sea caves, and hike up to viewpoints that offer stunning vistas of the islands below. Enjoy a nutritious picnic lunch on the beach, surrounded by nothing but nature and pristine ocean water. This is a must-do experience for anyone who loves the outdoors and wants to see the untouched, wild beauty of Thailand marine landscape."},{"day":3,"title":"Koh Phangan Day Trip","description":"Take a ferry across the sparkling waters to the neighboring island of Koh Phangan, known for its lush interior and serene beauty. Explore the local beaches, visit the island markets, and enjoy the authentic, chilled-out vibe that defines this destination. Spend your afternoon swimming in hidden coves and enjoying a quiet lunch at a beach shack overlooking the ocean. Return to Koh Samui in the late afternoon, having experienced the charm of a different island and feeling refreshed by the day trip."},{"day":4,"title":"Samui Leisure","description":"Today is dedicated entirely to relaxation and pampering, allowing you to enjoy the best of Koh Samui at your own pace. Start your morning with a world-class Thai spa treatment, designed to heal your body and calm your mind with local herbs and techniques. Afterward, wander over to the Fisherman Village for some boutique shopping and to enjoy a delightful lunch by the water. The rest of the day is yours to spend as you wish, whether by the resort pool or relaxing on the sand."},{"day":5,"title":"Island Highlights","description":"Explore the cultural side of the island with a visit to the iconic Big Buddha Temple, which overlooks the bay from its elevated position. Continue your tour to Wat Plai Laem, famous for its colorful, elaborate statues and serene atmosphere that is perfect for a quiet morning reflection. Spend your afternoon swimming at Chaweng Beach, known for its soft sand and calm, blue waters that are ideal for a dip. End your day by exploring the vibrant night market, where you can find unique crafts and street snacks."},{"day":6,"title":"Water Activities","description":"Choose your own adventure today with options like snorkeling in crystal-clear reefs or taking a private sailing trip around the island. For those who want to see the underwater world, diving is a popular option given the high visibility and abundance of marine life. If you prefer to stay above water, rent a stand-up paddleboard or simply enjoy a quiet day of swimming and relaxing on your resort private beach. Celebrate your final full day with an extravagant dinner, enjoying the best seafood that Koh Samui has to offer."},{"day":7,"title":"Departure","description":"Enjoy one last slow and peaceful breakfast at your resort, taking in the beautiful ocean view one final time. Pack your bags and pick up any last-minute gifts at the local boutiques before your scheduled transfer time. Our representative will take you to Samui International Airport in plenty of time for your flight home. Depart with a heart full of wonderful island memories and a refreshed spirit, knowing you have experienced the absolute best of the Gulf of Thailand."}]'::jsonb,
  '["Ang Thong Marine Park kayak","Big Buddha temple visit","Fisherman Village dinner","Koh Phangan day trip","Luxury beach resort"]'::jsonb,
  '["6 nights luxury resort stay","Daily breakfast","All ferry and local transfers","Marine park boat tours","Itinerary support"]'::jsonb,
  '["Flights","Visa","Lunch and dinner","Personal shopping"]'::jsonb,
  '["Check ferry schedules for seasonal changes","Carry comfortable swimwear and a dry bag for boat trips"]'::jsonb,
  '["Koh Samui","Koh Phangan"]'::jsonb,
  4.6, 540,
  'Koh Samui Island Tour | 360 Travellers',
  'Luxury island hopping in Koh Samui. Book with 360 Travellers.',
  '["koh samui tour","thailand island hopping","samui package","360 travellers"]'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM packages WHERE slug = 'samui-island-adventure-7d');
